const normalizeCityName = (value: string) =>
  value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[’]/g, "'")
    .replace(/\s+/g, " ")
    .trim()
    .toLowerCase();

export const findCity = (name: string) => {
  const normalized = normalizeCityName(name);
  return italianCities.find((city) => normalizeCityName(city.name) === normalized);
};
